import { Injectable, Logger } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { ContactsService } from '../contacts/contacts.service';
import { ConversationRepository } from '../omni-inbound/repositories/conversation.repository';
import { IdentityService } from '../omni-inbound/services/identity.service';
import { LivechatWidgetService } from './livechat-widget.service';
import {
  OmniEvents,
  LivechatVisitorIdentifiedEvent,
} from '../omni-inbound/domain/omni-events';

/**
 * ContactEnrichmentService — maps pre-chat form data to CRM Contact entity.
 *
 * Resolves the Gap-1 bug where visitor:identify only updated the
 * OmniConversation.customer subdocument but never enriched the Contact.
 *
 * Flow:
 *   1. Load WidgetConfig → read field-level `contactField` mapping rules
 *   2. Build Contact update payload from form data + mapping rules
 *   3. Find existing Contact (via conversation.contactId or email/phone dedup)
 *   4. Update or create Contact with mapped fields
 *   5. Ensure Conversation.contactId ↔ Contact.id (1:1 link)
 *   6. Broadcast update so CRM agent panel refreshes in realtime
 */
@Injectable()
export class ContactEnrichmentService {
  private readonly logger = new Logger(ContactEnrichmentService.name);

  /** Built-in Contact fields that can be mapped from pre-chat form */
  static readonly BUILTIN_CONTACT_FIELDS = [
    { key: 'firstName', label: 'Họ', type: 'string' },
    { key: 'lastName', label: 'Tên', type: 'string' },
    { key: 'emails', label: 'Email', type: 'array' },
    { key: 'phones', label: 'Số điện thoại', type: 'array' },
    { key: 'companyName', label: 'Công ty', type: 'string' },
    { key: 'title', label: 'Chức vụ', type: 'string' },
    { key: 'role', label: 'Vai trò', type: 'string' },
    { key: 'address', label: 'Địa chỉ', type: 'string' },
  ] as const;

  constructor(
    private readonly contactsService: ContactsService,
    private readonly conversationRepo: ConversationRepository,
    private readonly identityService: IdentityService,
    private readonly widgetService: LivechatWidgetService,
    private readonly eventEmitter: EventEmitter2,
  ) {}

  /**
   * Enrich a CRM Contact from pre-chat form submission.
   *
   * Steps:
   *   1. Load widget config → get field mapping rules (contactField per field)
   *   2. Build Contact update object from mapping rules
   *   3. Resolve existing Contact (conversation.contactId or email/phone dedup)
   *   4. Update existing Contact OR create new one
   *   5. Ensure Conversation.contactId = Contact.id (1:1 link)
   *   6. Broadcast changes for CRM realtime update
   */
  async enrichFromPreChat(
    event: LivechatVisitorIdentifiedEvent,
  ): Promise<void> {
    const {
      tenantId,
      visitorId,
      channelId,
      widgetId,
      conversationId,
      identityData,
    } = event;

    if (!identityData || Object.keys(identityData).length === 0) {
      this.logger.debug(
        `No identity data for visitor ${visitorId} — skipping enrichment`,
      );
      return;
    }

    try {
      // ── Step 1: Load widget config for field mapping rules ──────────
      const fieldMappings = await this.loadFieldMappings(widgetId);

      // ── Step 2: Build Contact update from mapping rules ─────────────
      const { contactUpdate, email, phone, displayName } =
        this.buildContactUpdate(identityData, fieldMappings);

      // ── Step 3: Resolve existing Contact ────────────────────────────
      let contactId: string | null = null;

      if (conversationId) {
        const conversation =
          await this.conversationRepo.findById(conversationId);
        contactId = conversation?.contactId ?? null;
      }

      // ── Step 3a: If we already have a contactId, enrich it ──────────
      if (contactId) {
        await this.enrichExistingContact(
          contactId,
          contactUpdate,
          email,
          phone,
        );
        this.logger.log(
          `Enriched existing Contact ${contactId} from pre-chat form`,
        );
      } else {
        // ── Step 3b: Search by email/phone dedup ──────────────────────
        contactId = await this.findOrCreateContact(
          tenantId,
          visitorId,
          contactUpdate,
          email,
          phone,
          displayName,
        );
      }

      // ── Step 5: Link Conversation ↔ Contact (1:1) ──────────────────
      if (conversationId && contactId) {
        await this.conversationRepo.updateContactId(conversationId, contactId);

        // Also update conversation.customer for display consistency
        await this.conversationRepo.updateCustomerInfo(conversationId, {
          ...(displayName ? { name: displayName } : {}),
          ...(email ? { email } : {}),
          ...(phone ? { phone } : {}),
        });

        // Update identity cache
        await this.identityService.updateIdentity(
          'livechat',
          channelId,
          visitorId,
          { contactId, conversationId },
          tenantId,
        );

        // ── Step 6: Broadcast for CRM realtime update ──────────────────
        this.eventEmitter.emit(OmniEvents.CONVERSATION_CUSTOMER_UPDATED, {
          tenantId,
          conversationId,
          contactId,
        });

        this.logger.log(
          `Linked Contact ${contactId} ↔ Conversation ${conversationId} (1:1)`,
        );
      }

      // ── Step 5b: Cache contactId even WITHOUT conversation ────────
      // When visitor submits pre-chat form before their first message,
      // conversationId is null. We still cache the contactId so that
      // ConversationService picks it up when the first message arrives
      // and creates the conversation linked to the correct contact
      // instead of creating a duplicate shadow contact.
      if (!conversationId && contactId) {
        await this.identityService.updateIdentity(
          'livechat',
          channelId,
          visitorId,
          { contactId, conversationId: null },
          tenantId,
        );
        this.logger.log(
          `Cached Contact ${contactId} for visitor ${visitorId} (no conversation yet)`,
        );
      }
    } catch (err: any) {
      // Enrichment failure must NOT block the chat flow
      this.logger.error(
        `Contact enrichment failed for visitor ${visitorId}: ${err.message}`,
        err.stack,
      );
    }
  }

  // ────────────────────────────────────────────────────────────────────────
  // Private Helpers
  // ────────────────────────────────────────────────────────────────────────

  /**
   * Load field definitions from widget config.
   * Falls back to default mappings if widget not found.
   */
  private async loadFieldMappings(
    widgetId?: string,
  ): Promise<Array<{ key: string; contactField?: string }>> {
    if (!widgetId) {
      return this.getDefaultFieldMappings();
    }

    try {
      const widget = await this.widgetService.getCachedWidget(widgetId);
      const fields = widget?.preChatForm?.fields;
      if (fields && fields.length > 0) {
        return fields;
      }
    } catch {
      this.logger.debug(
        `Widget ${widgetId} not found — using default mappings`,
      );
    }

    return this.getDefaultFieldMappings();
  }

  /**
   * Default field mappings when widget config is unavailable.
   * Maps the 3 standard fields: name→firstName, email→emails, phone→phones.
   */
  private getDefaultFieldMappings(): Array<{
    key: string;
    contactField: string;
  }> {
    return [
      { key: 'name', contactField: 'firstName' },
      { key: 'email', contactField: 'emails' },
      { key: 'phone', contactField: 'phones' },
    ];
  }

  /**
   * Build a Contact update object from form data + field mapping rules.
   *
   * Handles:
   * - String fields: direct assignment (firstName, companyName, etc.)
   * - Array fields: addToSet semantics (emails, phones)
   * - Custom fields: nested under customFields.{key}
   * - No contactField: skip (metadata only)
   */
  private buildContactUpdate(
    identityData: Record<string, any>,
    fieldMappings: Array<{ key: string; contactField?: string }>,
  ): {
    contactUpdate: Record<string, any>;
    email?: string;
    phone?: string;
    displayName?: string;
  } {
    const contactUpdate: Record<string, any> = {};
    const customFieldsUpdate: Record<string, any> = {};
    let email: string | undefined;
    let phone: string | undefined;
    let displayName: string | undefined;
    const nameParts: string[] = [];

    for (const fieldDef of fieldMappings) {
      const value = identityData[fieldDef.key];
      if (value === undefined || value === null || value === '') continue;

      const target = fieldDef.contactField;

      // Detect email/phone/name by contactField TARGET (dynamic mapping)
      // not by key name (admin-configured, could be anything).
      if (target === 'emails') email = String(value).toLowerCase();
      if (target === 'phones') phone = String(value);
      if (target === 'firstName' || target === 'lastName') {
        nameParts.push(String(value));
      }

      if (!target) continue; // No mapping → metadata only

      if (target.startsWith('customFields.')) {
        // Custom field: customFields.order_id → { order_id: value }
        const cfKey = target.replace('customFields.', '');
        customFieldsUpdate[cfKey] = value;
      } else if (target === 'emails') {
        contactUpdate.emails = [String(value).toLowerCase()];
      } else if (target === 'phones') {
        contactUpdate.phones = [String(value)];
      } else if (target === 'firstName' && !contactUpdate.firstName) {
        // If mapping to firstName and value looks like full name, split it
        const parts = this.splitName(String(value));
        contactUpdate.firstName = parts.firstName;
        if (parts.lastName) contactUpdate.lastName = parts.lastName;
      } else {
        contactUpdate[target] = value;
      }
    }

    // Build display name from mapped name parts (firstName + lastName)
    if (nameParts.length > 0) {
      displayName = nameParts.join(' ');
    }

    // Fallback: extract email/phone from identityData even without mapping
    // (for backward compatibility with forms that have standard keys)
    if (!email && identityData.email) email = String(identityData.email);
    if (!phone && identityData.phone) phone = String(identityData.phone);
    if (!displayName && identityData.name)
      displayName = String(identityData.name);

    if (Object.keys(customFieldsUpdate).length > 0) {
      contactUpdate.customFields = customFieldsUpdate;
    }

    return { contactUpdate, email, phone, displayName };
  }

  /**
   * Enrich an existing Contact with new data from pre-chat form.
   * Uses addToSet semantics for array fields (emails, phones).
   */
  private async enrichExistingContact(
    contactId: string,
    contactUpdate: Record<string, any>,
    email?: string,
    phone?: string,
  ): Promise<void> {
    const existing = await this.contactsService.findOne(contactId);
    if (!existing) return;

    // Merge array fields with existing values (addToSet)
    if (contactUpdate.emails) {
      contactUpdate.emails = [
        ...new Set([...(existing.emails ?? []), ...contactUpdate.emails]),
      ];
    }
    if (contactUpdate.phones) {
      contactUpdate.phones = [
        ...new Set([...(existing.phones ?? []), ...contactUpdate.phones]),
      ];
    }

    // Merge custom fields
    if (contactUpdate.customFields && existing.customFields) {
      contactUpdate.customFields = {
        ...existing.customFields,
        ...contactUpdate.customFields,
      };
    }

    // Only update if firstName is still 'Visitor' or shadow
    if (existing.isShadow && contactUpdate.firstName) {
      // Shadow contact promotion — will be handled by ContactsService.update()
    } else if (
      existing.firstName === 'Visitor' &&
      contactUpdate.firstName &&
      contactUpdate.firstName !== 'Visitor'
    ) {
      // Replace default 'Visitor' name
    } else {
      // Don't overwrite existing real name
      delete contactUpdate.firstName;
      delete contactUpdate.lastName;
    }

    if (Object.keys(contactUpdate).length > 0) {
      await this.contactsService.update(contactId, contactUpdate);
    }
  }

  /**
   * Find an existing Contact by email/phone dedup, or create a new one.
   * Returns the Contact ID.
   */
  private async findOrCreateContact(
    tenantId: string,
    visitorId: string,
    contactUpdate: Record<string, any>,
    email?: string,
    phone?: string,
    displayName?: string,
  ): Promise<string | null> {
    // Try dedup by email first
    if (email) {
      const byEmail = await this.contactsService.findByEmail(tenantId, email);
      if (byEmail) {
        // Merge visitor identity into existing contact
        try {
          await this.contactsService.mergeIdentity(byEmail.id, {
            channelType: 'livechat',
            senderId: visitorId,
          });
        } catch {
          // Identity may already exist — safe to ignore
        }

        // Update with form data
        await this.enrichExistingContact(
          byEmail.id,
          contactUpdate,
          email,
          phone,
        );
        this.logger.log(
          `Merged visitor ${visitorId} into Contact ${byEmail.id} by email ${email}`,
        );
        return byEmail.id;
      }
    }

    // Try dedup by senderId (livechat identity)
    const bySender = await this.contactsService.findBySenderId(
      tenantId,
      'livechat',
      visitorId,
    );
    if (bySender) {
      await this.enrichExistingContact(
        bySender.id,
        contactUpdate,
        email,
        phone,
      );
      this.logger.log(
        `Enriched existing Contact ${bySender.id} for visitor ${visitorId}`,
      );
      return bySender.id;
    }

    // No match → create new Contact
    const nameParts = this.splitName(displayName || 'Visitor');
    try {
      const newContact = await this.contactsService.create({
        ...nameParts,
        emails: email ? [email.toLowerCase()] : [],
        phones: phone ? [phone] : [],
        ...(contactUpdate.companyName
          ? { companyName: contactUpdate.companyName }
          : {}),
        ...(contactUpdate.title ? { title: contactUpdate.title } : {}),
        ...(contactUpdate.role ? { role: contactUpdate.role } : {}),
        ...(contactUpdate.address ? { address: contactUpdate.address } : {}),
        ...(contactUpdate.customFields
          ? { customFields: contactUpdate.customFields }
          : {}),
        isShadow: !email && !phone,
        omniIdentities: [{ channelType: 'livechat', senderId: visitorId }],
      } as any);

      this.logger.log(
        `Created Contact ${newContact.id} from pre-chat form for visitor ${visitorId}`,
      );
      return newContact.id;
    } catch (err: any) {
      this.logger.error(
        `Failed to create Contact for visitor ${visitorId}: ${err.message}`,
      );
      return null;
    }
  }

  /**
   * Split a full name string into firstName + lastName.
   */
  private splitName(fullName: string): {
    firstName: string;
    lastName?: string;
  } {
    const parts = fullName.trim().split(/\s+/);
    if (parts.length === 1) {
      return { firstName: parts[0] };
    }
    return {
      firstName: parts[0],
      lastName: parts.slice(1).join(' '),
    };
  }
}

import { Injectable, Logger, Inject, forwardRef } from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';
import { OnEvent } from '@nestjs/event-emitter';
import { ulid } from 'ulid';

import { OmniPayload } from '../domain/omni-payload';
import {
  ConversationCommand,
  BotGeneratedReplyEvent,
  CustomerMessagePayload,
  AssignAgentPayload,
  ChangeStatusPayload,
  UpdateBotStatePayload,
} from './conversation-command.types';
import {
  CONV_OPS_QUEUE,
  CONV_OPS_MAX_ATTEMPTS,
  BOT_GENERATED_REPLY_EVENT,
} from './conversation-ops.constants';
import type { ConversationOpsProcessor } from './conversation-ops.processor';

/**
 * ConversationCommandService — builds and enqueues typed commands
 * into the conversation-ops BullMQ queue.
 *
 * This is the ONLY entry point for creating conversation operations.
 * No service should mutate conversation state directly; instead they
 * call methods on this service which enqueue the appropriate command.
 *
 * The service also listens for decoupled events (e.g. bot.generated_reply)
 * and converts them into commands automatically.
 */
@Injectable()
export class ConversationCommandService {
  private readonly logger = new Logger(ConversationCommandService.name);

  constructor(
    @InjectQueue(CONV_OPS_QUEUE) private readonly opsQueue: Queue,
    @Inject(
      forwardRef(
        () => require('./conversation-ops.processor').ConversationOpsProcessor,
      ),
    )
    private readonly processor: ConversationOpsProcessor,
  ) {}

  /**
   * Enqueue a CUSTOMER_MESSAGE command.
   *
   * Called by ConversationService after identity resolution and
   * conversation find-or-create logic (reads only). The processor
   * will handle message persistence, aggregate update, and event emission.
   */
  async enqueueCustomerMessage(
    conversationId: string,
    tenantId: string,
    omniPayload: OmniPayload,
    messageDedupId: string,
    idemKey: string,
  ): Promise<void> {
    const operationId = ulid();

    const command: ConversationCommand = {
      operationId,
      sourceId: `inbound:${messageDedupId}`,
      type: 'CUSTOMER_MESSAGE',
      conversationId,
      tenantId,
      payload: {
        omniPayload,
        messageDedupId,
        idemKey,
      } satisfies CustomerMessagePayload,
      createdAt: new Date().toISOString(),
    };

    await this.enqueue(command);

    this.logger.debug(
      `[CONV-CMD] Enqueued CUSTOMER_MESSAGE op=${operationId} conv=${conversationId}`,
    );
  }

  /**
   * Listen for bot.generated_reply events and convert to BOT_REPLY command.
   *
   * This decoupling allows any future bot source (AI Agent, Flow Builder,
   * External Automation) to emit the same event without touching the
   * aggregate architecture.
   */
  @OnEvent(BOT_GENERATED_REPLY_EVENT)
  async handleBotGeneratedReply(event: BotGeneratedReplyEvent): Promise<void> {
    const operationId = ulid();

    const command: ConversationCommand = {
      operationId,
      sourceId: `bot:${event.inboundMessageId}`,
      type: 'BOT_REPLY',
      conversationId: event.conversationId,
      tenantId: event.tenantId,
      payload: {
        messages: event.messages,
        handoff: event.handoff,
        handoffMeta: event.handoffMeta,
        sessionId: event.sessionId,
        status: event.status,
        inboundMessageId: event.inboundMessageId,
        afterTimestamp: event.afterTimestamp,
      },
      createdAt: new Date().toISOString(),
    };

    await this.enqueue(command);

    this.logger.debug(
      `[CONV-CMD] Enqueued BOT_REPLY op=${operationId} conv=${event.conversationId} ` +
        `msgs=${event.messages?.length ?? 0} handoff=${event.handoff}`,
    );
  }

  // ── Phase 2 Commands ──────────────────────────────────────────────

  /**
   * Enqueue an ASSIGN_AGENT command.
   * Handles agent assignment, group assignment, unassignment, and takeover.
   */
  async enqueueAssignAgent(
    conversationId: string,
    tenantId: string,
    payload: AssignAgentPayload,
  ): Promise<string> {
    const operationId = ulid();

    await this.enqueue({
      operationId,
      sourceId: `assign:${conversationId}:${operationId}`,
      type: 'ASSIGN_AGENT',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    });

    this.logger.debug(
      `[CONV-CMD] Enqueued ASSIGN_AGENT op=${operationId} conv=${conversationId} ` +
        `agent=${payload.agentId} reason=${payload.reason}`,
    );

    return operationId;
  }

  /**
   * Enqueue a CHANGE_STATUS command.
   * Handles open, pending, resolved, closed transitions.
   */
  async enqueueChangeStatus(
    conversationId: string,
    tenantId: string,
    payload: ChangeStatusPayload,
  ): Promise<string> {
    const operationId = ulid();

    await this.enqueue({
      operationId,
      sourceId: `status:${conversationId}:${operationId}`,
      type: 'CHANGE_STATUS',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    });

    this.logger.debug(
      `[CONV-CMD] Enqueued CHANGE_STATUS op=${operationId} conv=${conversationId} ` +
        `status=${payload.newStatus} source=${payload.resolveSource}`,
    );

    return operationId;
  }

  /**
   * Enqueue an UPDATE_BOT_STATE command.
   * Handles enable/disable bot, error state, auto-init.
   */
  async enqueueUpdateBotState(
    conversationId: string,
    tenantId: string,
    payload: UpdateBotStatePayload,
  ): Promise<string> {
    const operationId = ulid();

    await this.enqueue({
      operationId,
      sourceId: `bot-state:${conversationId}:${operationId}`,
      type: 'UPDATE_BOT_STATE',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    });

    this.logger.debug(
      `[CONV-CMD] Enqueued UPDATE_BOT_STATE op=${operationId} conv=${conversationId} ` +
        `reason=${payload.reason}`,
    );

    return operationId;
  }

  // ── Inline Execution (synchronous controller path) ────────────────
  //
  // Industry standard (Zendesk, HubSpot, Salesforce):
  // Single-record mutations return the updated document synchronously.
  // These methods acquire the aggregate lock and execute inline
  // (bypassing BullMQ queue) for controller use.
  //
  // Background processors should use the enqueue* methods above.
  // ──────────────────────────────────────────────────────────────────

  /**
   * Execute ASSIGN_AGENT synchronously. Returns updated conversation.
   * Use from controllers that need the updated document in the response.
   */
  async executeAssignAgent(
    conversationId: string,
    tenantId: string,
    payload: AssignAgentPayload,
  ): Promise<any> {
    const operationId = ulid();
    const cmd: ConversationCommand = {
      operationId,
      sourceId: `assign:${conversationId}:${operationId}`,
      type: 'ASSIGN_AGENT',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    };
    this.logger.debug(
      `[CONV-CMD] Inline ASSIGN_AGENT op=${operationId} conv=${conversationId} agent=${payload.agentId}`,
    );
    return this.processor.executeInline(cmd);
  }

  /**
   * Execute CHANGE_STATUS synchronously. Returns updated conversation.
   */
  async executeChangeStatus(
    conversationId: string,
    tenantId: string,
    payload: ChangeStatusPayload,
  ): Promise<any> {
    const operationId = ulid();
    const cmd: ConversationCommand = {
      operationId,
      sourceId: `status:${conversationId}:${operationId}`,
      type: 'CHANGE_STATUS',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    };
    this.logger.debug(
      `[CONV-CMD] Inline CHANGE_STATUS op=${operationId} conv=${conversationId} status=${payload.newStatus}`,
    );
    return this.processor.executeInline(cmd);
  }

  /**
   * Execute UPDATE_BOT_STATE synchronously. Returns updated conversation.
   */
  async executeUpdateBotState(
    conversationId: string,
    tenantId: string,
    payload: UpdateBotStatePayload,
  ): Promise<any> {
    const operationId = ulid();
    const cmd: ConversationCommand = {
      operationId,
      sourceId: `bot-state:${conversationId}:${operationId}`,
      type: 'UPDATE_BOT_STATE',
      conversationId,
      tenantId,
      payload,
      createdAt: new Date().toISOString(),
    };
    this.logger.debug(
      `[CONV-CMD] Inline UPDATE_BOT_STATE op=${operationId} conv=${conversationId} reason=${payload.reason}`,
    );
    return this.processor.executeInline(cmd);
  }

  /**
   * Core enqueue — adds a command to the conversation-ops queue.
   * Uses operationId as jobId for BullMQ-level dedup.
   */
  private async enqueue(command: ConversationCommand): Promise<void> {
    await this.opsQueue.add(command.type, command, {
      jobId: command.operationId,
      attempts: CONV_OPS_MAX_ATTEMPTS,
      backoff: { type: 'exponential', delay: 2000 },
      removeOnComplete: { count: 1000 },
      removeOnFail: false, // Keep failed jobs for DLQ inspection
    });
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import axios from 'axios';
import { BotReplyRequest, BotAcceptResponse } from './bot-processing.types';

@Injectable()
export class BotApiService {
  private readonly logger = new Logger(BotApiService.name);

  constructor(private readonly configService: ConfigService) {}

  /**
   * Fire-and-forget: send request to bot, expect immediate 200 {accepted: true}.
   * Bot will process async and POST results back to callbackUrl.
   */
  async dispatch(payload: BotReplyRequest): Promise<BotAcceptResponse> {
    const baseUrl = this.resolveBotBaseUrl();
    const endpoint = `${baseUrl}/api/bot/typebot/reply`;
    const secret = this.configService.get<string>('CRM_BOT_INTERNAL_SECRET');

    this.logger.log(
      `[BOT-API] Dispatching to crm-bot: endpoint=${endpoint}, ` +
        `conv=${payload.conversationId}, msg=${payload.inboundMessageId}, ` +
        `sessionId=${payload.sessionId}, channel=${payload.channel}`,
    );

    try {
      const response = await axios.post<BotAcceptResponse>(endpoint, payload, {
        timeout: 3000, // Only waiting for acceptance, not processing
        headers: {
          'content-type': 'application/json',
          ...(secret ? { 'x-crm-internal-secret': secret } : {}),
        },
      });

      this.logger.log(
        `[BOT-API] ✓ crm-bot response: status=${response.status}, ` +
          `data=${JSON.stringify(response.data)}, conv=${payload.conversationId}`,
      );

      return response.data;
    } catch (error: any) {
      const status = error?.response?.status;
      const data = error?.response?.data;
      this.logger.error(
        `[BOT-API] ✗ crm-bot dispatch FAILED: status=${status}, ` +
          `data=${JSON.stringify(data)}, message=${error?.message}, ` +
          `endpoint=${endpoint}, conv=${payload.conversationId}`,
      );
      throw error;
    }
  }

  /**
   * Build the callback URL that bot will POST results to.
   *
   * Prioritizes CRM_API_INTERNAL_URL because crm-bot validates the callback
   * origin against its own CRM_API_INTERNAL_URL env var (SSRF protection).
   * Using the public URL would cause an origin mismatch in Docker/K8s
   * where internal and public URLs differ.
   */
  resolveCallbackUrl(): string {
    const raw =
      this.configService.get<string>('CRM_API_INTERNAL_URL', { infer: true }) ||
      this.configService.get<string>('CRM_API_PUBLIC_URL', { infer: true }) ||
      this.configService.get<string>('API_BASE_URL', { infer: true }) ||
      'http://localhost:3000';
    const apiPrefix =
      this.configService.get<string>('API_PREFIX', { infer: true }) || 'api';
    return `${raw.replace(/\/+$/, '')}/${apiPrefix}/v1/bot-callback/reply`;
  }

  private resolveBotBaseUrl(): string {
    const raw =
      this.configService.get<string>('CRM_BOT_URL', { infer: true }) ||
      this.configService.get<string>('BOT_SERVICE_URL', { infer: true }) ||
      'http://localhost:4203';
    return raw.replace(/\/+$/, '');
  }
}

import {
  Controller,
  Get,
  Patch,
  Post,
  Delete,
  Param,
  Query,
  Body,
  HttpCode,
  HttpStatus,
  Logger,
  NotFoundException,
  BadRequestException,
} from '@nestjs/common';
import { ClsService } from 'nestjs-cls';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { Throttle } from '@nestjs/throttler';
import { ConversationRepository } from '../repositories/conversation.repository';
import { MessageRepository } from '../repositories/message.repository';
import { OutboundService } from '../../omni-outbound/outbound.service';
import { NoteService } from '../services/note.service';
import { ActivityService } from '../services/activity.service';
import { ConversationService } from '../services/conversation.service';
import { ConversationQueryService } from '../services/conversation-query.service';
import { ConversionService } from '../services/conversion.service';
import { ConversationLockService } from '../services/conversation-lock.service';
import { TimelineQueryDto } from '../dto/timeline-query.dto';
import { LinkMessagesDto } from '../dto/link-messages.dto';
import { UsersService } from '../../users/users.service';
import { TenantsService } from '../../tenants/tenants.service';
import { FilesService } from '../../files/files.service';
import { RequirePermission } from '../../common/permissions';
import { AssignmentAuditLogRepository } from '../repositories/omni-assignment-audit-log.repository';
import { AgentPresenceService } from '../services/agent-presence.service';
import { AssignmentService } from '../services/assignment.service';
import { ConversationCommandService } from '../aggregate/conversation-command.service';

/**
 * REST API for omni-channel conversations and messages.
 *
 * Endpoints:
 *   GET   /omni/conversations              — paginated list
 *   GET   /omni/conversations/:id          — single conversation detail
 *   GET   /omni/conversations/:id/messages — paginated messages
 *   PATCH /omni/conversations/:id/status   — resolve / reopen session
 *   POST  /omni/conversations/:id/tags     — add tag
 *   PATCH /omni/conversations/:id/claim    — claim / assign agent
 *   PATCH /omni/conversations/:id/read     — mark as read (reset unread count)
 *   PATCH /omni/conversations/:id/assign   — assign / reassign agent
 *   PATCH /omni/conversations/:id/unassign — remove agent assignment
 */
@Controller({ path: 'omni', version: '1' })
export class OmniController {
  private readonly logger = new Logger(OmniController.name);

  constructor(
    private readonly conversationRepo: ConversationRepository,
    private readonly messageRepo: MessageRepository,
    private readonly conversationService: ConversationService,
    private readonly queryService: ConversationQueryService,
    private readonly conversionService: ConversionService,
    private readonly outboundService: OutboundService,
    private readonly noteService: NoteService,
    private readonly activityService: ActivityService,
    private readonly conversationLockService: ConversationLockService,
    private readonly cls: ClsService,
    private readonly eventEmitter: EventEmitter2,
    private readonly usersService: UsersService,
    private readonly tenantsService: TenantsService,
    private readonly filesService: FilesService,
    private readonly auditLogRepo: AssignmentAuditLogRepository,
    private readonly agentPresenceService: AgentPresenceService,
    private readonly assignmentService: AssignmentService,
    private readonly conversationCommandService: ConversationCommandService,
  ) {}

  // ─── Routing Trace (production debugging) ────────────────────

  /**
   * GET /omni/conversations/:id/routing-trace
   *
   * Returns the assignment audit log for a specific conversation.
   * Shows every routing decision (assign, queue, fail) in chronological
   * order — the primary tool for debugging routing issues in production
   * without reading logs or code.
   */
  @Get('conversations/:id/routing-trace')
  @RequirePermission('view', 'contacts')
  async getRoutingTrace(
    @Param('id') conversationId: string,
    @Query('limit') limit = '10',
    @Query('cursor') cursor?: string,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${conversationId} not found`);
    }

    const { entries, nextCursor } = await this.auditLogRepo.findByConversation(
      tenantId,
      conversationId,
      Math.min(parseInt(limit, 10), 50),
      cursor || undefined,
    );

    return {
      conversationId,
      entries,
      total: entries.length,
      nextCursor,
    };
  }

  /**
   * GET /omni/routing-history
   *
   * Global routing audit log search across all conversations.
   * Supports query filtering by conversationId (partial match),
   * outcome (assigned/queued/failed), and limit.
   *
   * Powers the global Routing History page for production debugging
   * when a customer reports an issue and you need to trace without
   * knowing the exact conversation.
   */
  @Get('routing-history')
  @RequirePermission('view', 'contacts')
  async getRoutingHistory(
    @Query('search') search?: string,
    @Query('outcome') outcome?: 'assigned' | 'queued' | 'failed',
    @Query('limit') limit = '50',
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    const entries = await this.auditLogRepo.search(
      tenantId,
      {
        conversationId: search || undefined,
        outcome: outcome || undefined,
      },
      Math.min(parseInt(limit, 10), 100),
    );

    return {
      entries,
      total: entries.length,
    };
  }

  // ─── Conversations ────────────────────────────────────────────

  /**
   * List conversations for the current tenant, paginated.
   * Supports filtering by status, channelType, assignedAgent, and search.
   */
  @Get('conversations')
  @RequirePermission('view', 'contacts')
  async listConversations(
    @Query('cursor') cursor?: string,
    @Query('limit') limit = '20',
    @Query('status') status?: string,
    @Query('channels') channels?: string,
    @Query('assignedTo') assignedTo?: string,
    @Query('sla') sla?: string,
    @Query('tags') tags?: string,
    @Query('isVip') isVip?: string,
    @Query('hasUnread') hasUnread?: string,
    @Query('search') search?: string,
    @Query('contactId') contactId?: string,
    @Query('page') page?: string,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    const userId = this.cls.get<string>('userId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    // ── contactId shortcut: return paginated conversations for a CRM contact ──
    if (contactId) {
      return this.conversationRepo.findByContactId(
        tenantId,
        contactId,
        page ? parseInt(page, 10) : 1,
        Math.min(parseInt(limit, 10), 50),
      );
    }

    const statusFilter = status ? status.split(',') : ['open', 'pending'];
    // Normalize channels to lowercase for case-insensitive matching
    const channelFilter = channels
      ? channels.split(',').map((ch) => ch.toLowerCase())
      : undefined;
    const slaFilter = sla ? sla.split(',') : undefined;
    const tagsFilter = tags ? tags.split(',') : undefined;

    let assignedAgent: string | null | undefined = undefined;
    let assignedGroup: string | null | undefined = undefined;
    let unassigned = false;

    if (assignedTo === 'me') {
      assignedAgent = userId;
    } else if (assignedTo === 'unassigned') {
      unassigned = true;
    } else if (assignedTo?.startsWith('group:')) {
      assignedGroup = assignedTo.substring(6);
    }

    const result = await this.conversationRepo.findCursorPaginated(
      {
        tenantId,
        status: statusFilter,
        channels: channelFilter,
        assignedAgent,
        assignedGroup,
        unassigned,
        sla: slaFilter,
        tags: tagsFilter,
        isVip: isVip === 'true' ? true : isVip === 'false' ? false : undefined,
        hasUnread:
          hasUnread === 'true'
            ? true
            : hasUnread === 'false'
              ? false
              : undefined,
        search,
        cursor,
      },
      parseInt(limit, 10), // cap will be applied in repo
    );

    // Resolve display-friendly resolver info for list cards (name/email),
    // so UI does not have to show raw IDs.
    // Batch both resolvedByAgentId and assignedAgentId into one user lookup.
    const resolverIds = Array.from(
      new Set(
        result.data
          .map((c) => c.resolvedByAgentId)
          .filter((id): id is string => Boolean(id)),
      ),
    );

    const assignedAgentIds = Array.from(
      new Set(
        result.data
          .map((c) => c.assignedAgentId)
          .filter((id): id is string => Boolean(id)),
      ),
    );

    const allAgentIds = Array.from(
      new Set([...resolverIds, ...assignedAgentIds]),
    );

    let agentMap = new Map<
      string,
      { name: string | null; email: string | null }
    >();
    if (allAgentIds.length > 0) {
      const users = await this.usersService.findByIdsGlobal(allAgentIds);
      agentMap = new Map(
        users.map((u) => {
          const fullName = [u.firstName, u.lastName]
            .filter(Boolean)
            .join(' ')
            .trim();
          return [
            String(u.id),
            { name: fullName || null, email: u.email ?? null },
          ];
        }),
      );
    }

    const enrichedData = result.data.map((c) => {
      const resolvedFromPopulate = c.resolvedByAgent
        ? {
            name:
              [c.resolvedByAgent.firstName, c.resolvedByAgent.lastName]
                .filter(Boolean)
                .join(' ')
                .trim() || null,
            email: c.resolvedByAgent.email ?? null,
          }
        : null;

      const resolvedFromMap = c.resolvedByAgentId
        ? (agentMap.get(c.resolvedByAgentId) ?? null)
        : null;

      const resolvedDisplay = resolvedFromPopulate ?? resolvedFromMap;

      const assignedDisplay = c.assignedAgentId
        ? (agentMap.get(c.assignedAgentId) ?? null)
        : null;

      // Destructure out populated Mongoose objects — frontend expects
      // string IDs only, not full user objects.
      const { assignedAgent: _aa, resolvedByAgent: _ra, ...rest } = c;

      return {
        ...rest,
        resolvedByAgentName: resolvedDisplay?.name ?? null,
        resolvedByAgentEmail: resolvedDisplay?.email ?? null,
        assignedAgentName: assignedDisplay?.name ?? null,
      };
    });

    this.logger.debug(`listConversations: found ${result.data.length} items`);
    return {
      ...result,
      data: enrichedData,
    };
  }

  // ─── Batch Messages (cross-module) ──────────────────────────────

  /**
   * Fetch messages by an array of IDs.
   * Used by Deal/Ticket detail pages to display linked chat messages.
   */
  @Get('messages/batch')
  @RequirePermission('view', 'contacts')
  async getMessagesBatch(@Query('ids') ids?: string) {
    if (!ids) {
      throw new BadRequestException('ids query parameter is required');
    }

    const idArray = ids.split(',').filter(Boolean).slice(0, 50);
    if (idArray.length === 0) {
      return { data: [] };
    }

    const messages = await this.messageRepo.findByIds(idArray);
    return { data: messages };
  }

  /**
   * Get a single conversation by ID (with customer info).
   */
  @Get('conversations/:id')
  @RequirePermission('view', 'contacts')
  async getConversation(@Param('id') id: string) {
    const conversation = await this.conversationRepo.findById(id);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${id} not found`);
    }
    return conversation;
  }

  /**
   * Update customer info (name, email, phone) for a conversation.
   */
  @Patch('conversations/:id/customer')
  @RequirePermission('edit', 'contacts')
  @HttpCode(HttpStatus.OK)
  async updateCustomer(
    @Param('id') id: string,
    @Body() body: { name?: string; email?: string; phone?: string },
  ) {
    const updated = await this.conversationRepo.updateCustomerInfo(id, body);
    if (!updated) {
      throw new NotFoundException(`Conversation ${id} not found`);
    }

    const tenantId = this.cls.get<string>('tenantId');
    const agentId = this.cls.get<string>('userId');

    // Emit event to update UI via socket
    this.eventEmitter.emit('omni.conversation.customer_updated', {
      tenantId,
      conversationId: id,
      customer: updated.customer,
      agentId,
    });

    return updated;
  }

  // ─── Messages ─────────────────────────────────────────────────

  /**
   * Get paginated messages for a conversation.
   * Returns oldest-first for chat display.
   *
   * Enriches media messages that have `metadata.media.fileId` but no
   * `mediaUrl`/`mediaProxyUrl` (e.g. livechat agent-sent images) with
   * presigned S3 download URLs so the frontend can render them.
   */
  @Get('conversations/:id/messages')
  @RequirePermission('view', 'contacts')
  async getMessages(
    @Param('id') conversationId: string,
    @Query('page') page = '1',
    @Query('limit') limit = '50',
  ) {
    // Verify conversation exists
    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${conversationId} not found`);
    }

    const result = await this.messageRepo.findByConversation(
      conversationId,
      parseInt(page, 10),
      Math.min(parseInt(limit, 10), 100),
    );

    // Enrich media messages that have fileId but no resolved URL
    const enriched = await this.enrichMediaUrls(result.data);

    return { ...result, data: enriched };
  }

  @Get('conversations/:id/sync')
  @RequirePermission('view', 'contacts')
  async syncConversation(
    @Param('id') conversationId: string,
    @Query('afterVersion') afterVersion?: string,
    @Query('afterMessageId') afterMessageId?: string,
    @Query('afterCreatedAt') afterCreatedAt?: string,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${conversationId} not found`);
    }

    const cursorCreatedAt = afterCreatedAt ? new Date(afterCreatedAt) : null;
    const canDeltaSync =
      !!afterMessageId &&
      !!cursorCreatedAt &&
      !Number.isNaN(cursorCreatedAt.getTime());

    const messageResult = canDeltaSync
      ? await this.messageRepo.findByConversationIdWithCursor({
          conversationId,
          limit: 100,
          direction: 'future',
          cursor: {
            id: afterMessageId,
            createdAt: cursorCreatedAt,
          },
        })
      : await this.messageRepo.findByConversation(conversationId, 1, 100);
    const messages = messageResult.data;
    const hasMore =
      'hasMore' in messageResult
        ? messageResult.hasMore
        : messageResult.hasNextPage;

    // Enrich media messages with presigned URLs
    const enrichedMessages = await this.enrichMediaUrls(messages);

    return {
      mode: canDeltaSync ? 'delta' : 'snapshot',
      conversationId,
      afterVersion: afterVersion ? Number(afterVersion) : null,
      afterMessageId: afterMessageId ?? null,
      currentVersion: Date.now(),
      conversation,
      messages: enrichedMessages,
      hasMore,
      lock: await this.conversationLockService.getLock(
        tenantId,
        conversationId,
      ),
    };
  }

  @Post('conversations/batch-sync')
  @RequirePermission('view', 'contacts')
  @HttpCode(HttpStatus.OK)
  async batchSyncConversations(
    @Body()
    body: {
      conversationIds?: string[];
      lastUpdated?: string;
    },
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    const conversationIds = Array.from(
      new Set((body.conversationIds ?? []).filter(Boolean)),
    ).slice(0, 50);

    if (conversationIds.length === 0) {
      return {
        conversations: [],
        serverTime: new Date().toISOString(),
      };
    }

    const lastUpdatedAt = body.lastUpdated ? new Date(body.lastUpdated) : null;
    const conversations = await this.conversationRepo.findByIds(
      tenantId,
      conversationIds,
    );

    return {
      conversations: conversations.map((conversation) => ({
        id: conversation.id,
        status: conversation.status,
        lastMessage: conversation.lastMessage,
        lastMessageAt: conversation.lastMessageAt,
        unreadCount: conversation.unreadCount,
        assignedAgentId: conversation.assignedAgentId,
        assignedGroupId: conversation.assignedGroupId,
        tags: conversation.tags,
        updatedAt: conversation.updatedAt,
        hasChangesSince:
          !!lastUpdatedAt &&
          !!conversation.updatedAt &&
          new Date(conversation.updatedAt).getTime() > lastUpdatedAt.getTime(),
      })),
      serverTime: new Date().toISOString(),
    };
  }

  @Get('conversations/:id/timeline')
  @RequirePermission('view', 'contacts')
  async getConversationTimeline(
    @Param('id') conversationId: string,
    @Query() query: TimelineQueryDto,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    return this.queryService.getConversationTimeline({
      tenantId,
      conversationId,
      query,
    });
  }

  /**
   * Get the full cross-conversation message history for a customer.
   *
   * Returns all messages from ALL past and current conversations for
   * the same customer thread (same externalId), oldest-first.
   * This gives agents full context regardless of how many sessions
   * were opened and closed.
   *
   * @param convPage  Which batch of past conversations to load (default: 1 = most recent past batch)
   * @param convLimit How many past conversations per batch (default 5 — a reasonable scroll chunk)
   * @param msgPage   Pagination within the selected conversation batch
   * @param limit     Messages per page
   */
  @Get('conversations/:id/history')
  @RequirePermission('view', 'contacts')
  async getConversationHistory(
    @Param('id') conversationId: string,
    @Query('convPage') convPage = '1',
    @Query('convLimit') convLimit = '5',
    @Query('page') page = '1',
    @Query('limit') limit = '50',
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${conversationId} not found`);
    }

    // ── Step 1: Get the total count of past sessions for this customer ──────
    const allConversations = await this.conversationRepo.findAllByExternalId(
      tenantId,
      conversation.channelType,
      conversation.channelAccount!,
      conversation.externalConversationId,
    );

    // Exclude the current (active) conversation — it's loaded separately
    const pastConversations = allConversations.filter(
      (c) => c.id !== conversationId,
    );
    const totalConversations = pastConversations.length;

    // ── Step 2: Paginate the conversation set (newest-first batches) ─────────
    const cp = Math.max(1, parseInt(convPage, 10));
    const cl = Math.min(parseInt(convLimit, 10), 20);
    const start = (cp - 1) * cl; // newest past first → slice from the end
    const pagedConversations = pastConversations.slice(
      Math.max(0, totalConversations - start - cl),
      Math.max(0, totalConversations - start),
    );

    const conversationIds = pagedConversations.map((c) => c.id);

    // ── Step 3: Fetch messages for this slice only ───────────────────────────
    const messages =
      conversationIds.length > 0
        ? await this.messageRepo.findByConversationIds(
            conversationIds,
            parseInt(page, 10),
            Math.min(parseInt(limit, 10), 100),
          )
        : { data: [], total: 0, page: 1, limit: 50 };

    const resolverIds = Array.from(
      new Set(
        pagedConversations
          .map((c) => c.resolvedByAgentId)
          .filter((id): id is string => Boolean(id)),
      ),
    );

    let resolverMap = new Map<
      string,
      { name: string | null; email: string | null }
    >();
    if (resolverIds.length > 0) {
      const users = await this.usersService.findByIdsGlobal(resolverIds);
      resolverMap = new Map(
        users.map((u) => {
          const fullName = [u.firstName, u.lastName]
            .filter(Boolean)
            .join(' ')
            .trim();
          return [
            String(u.id),
            { name: fullName || null, email: u.email ?? null },
          ];
        }),
      );
    }

    // ── Step 4: Build session metadata ──────────────────────────────────────
    const sessions = pagedConversations.map((c) => {
      const resolvedFromPopulate = c.resolvedByAgent
        ? {
            name:
              [c.resolvedByAgent.firstName, c.resolvedByAgent.lastName]
                .filter(Boolean)
                .join(' ')
                .trim() || null,
            email: c.resolvedByAgent.email ?? null,
          }
        : null;

      const resolvedFromMap = c.resolvedByAgentId
        ? (resolverMap.get(c.resolvedByAgentId) ?? null)
        : null;

      const resolvedDisplay = resolvedFromPopulate ?? resolvedFromMap;

      return {
        id: c.id,
        status: c.status,
        createdAt: c.createdAt,
        resolvedAt: c.resolvedAt,
        resolvedByAgentId: c.resolvedByAgentId,
        resolveReason: c.resolveReason,
        resolveNote: c.resolveNote,
        resolveSource: c.resolveSource,
        lastMessage: c.lastMessage,
        resolvedByAgent: c.resolvedByAgent,
        resolvedByAgentName: resolvedDisplay?.name ?? null,
        resolvedByAgentEmail: resolvedDisplay?.email ?? null,
      };
    });

    return {
      ...messages,
      totalConversations,
      convPage: cp,
      convLimit: cl,
      hasMoreHistory: start + cl < totalConversations,
      sessions,
    };
  }

  @Post('conversations/:id/messages')
  // Per-tenant cap: 60 outbound messages / minute / user. Prevents one
  // agent (or compromised session) from spam-sending across providers
  // and tripping provider-side rate limits that would block the whole
  // tenant.
  @Throttle({ default: { limit: 60, ttl: 60_000 } })
  @RequirePermission('edit', 'contacts')
  @HttpCode(HttpStatus.CREATED)
  async sendMessage(
    @Param('id') conversationId: string,
    @Body('content') content: string,
    @Body('messageType') messageType?: string,
    @Body('idempotencyKey') idempotencyKey?: string,
    @Body('clientMessageId') clientMessageId?: string,
    @Body('source') source?: string,
  ) {
    if (!content) {
      throw new BadRequestException('Content is required');
    }

    const tenantId = this.cls.get<string>('tenantId');
    const agentId = this.cls.get<string>('userId');

    if (!tenantId || !agentId) {
      throw new BadRequestException('User or Tenant context not found');
    }

    try {
      return await this.outboundService.sendAgentMessage({
        tenantId,
        conversationId,
        agentId,
        content,
        messageType,
        source: source ?? 'crm_api',
        transport: 'http',
        idempotencyKey,
        clientMessageId,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Failed to send message: ${errorMessage}`);
      throw new BadRequestException(errorMessage);
    }
  }

  @Post('conversations/:id/email-reply')
  @Throttle({ default: { limit: 30, ttl: 60_000 } })
  @RequirePermission('edit', 'contacts')
  @HttpCode(HttpStatus.CREATED)
  async emailReply(
    @Param('id') conversationId: string,
    @Body()
    payload: {
      to: string[];
      cc?: string[];
      bcc?: string[];
      subject: string;
      htmlBody: string;
      inReplyTo?: string;
      references?: string[];
      attachments?: { url: string; filename: string; contentType: string }[];
    },
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    const agentId = this.cls.get<string>('userId');

    if (!tenantId || !agentId) {
      throw new BadRequestException('User or Tenant context not found');
    }

    try {
      return await this.outboundService.sendEmailReply({
        tenantId,
        conversationId,
        agentId,
        ...payload,
      });
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : typeof error === 'string'
            ? error
            : JSON.stringify(error);
      this.logger.error(`Failed to send email reply: ${message}`);
      throw new BadRequestException(message);
    }
  }

  /**
   * GET /omni/conversations/:id/reply-window
   * Returns the platform reply window status for this conversation.
   * The frontend uses this to lock/unlock the chat input.
   */
  @Get('conversations/:id/reply-window')
  @RequirePermission('view', 'contacts')
  async getReplyWindowStatus(@Param('id') conversationId: string) {
    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new NotFoundException(`Conversation ${conversationId} not found`);
    }

    return this.outboundService.getReplyWindowStatus(conversation);
  }

  @Get('conversations/:id/lock')
  @RequirePermission('view', 'contacts')
  async getConversationLock(@Param('id') conversationId: string) {
    const tenantId = this.cls.get<string>('tenantId');
    if (!tenantId) {
      throw new BadRequestException('Tenant context not found');
    }

    return {
      lock: await this.conversationLockService.getLock(
        tenantId,
        conversationId,
      ),
    };
  }

