      tenantId,
      channelType: 'livechat', // Agent reactions are always internal
      channelId: '',
      messageId: data.messageId,
      externalMessageId: data.messageId,
      senderId: userId,
      senderType: 'agent',
      emoji: data.emoji,
      action: data.action ?? 'react',
      timestamp: new Date(),
    });

