  /**
   * Broadcast agent assignment changes to all agents.
   */
  @OnEvent('omni.conversation.assigned')
  async handleAssignmentChanged(event: {
    tenantId: string;
    conversationId: string;
    agentId: string | null;
    oldAgentId: string | null;
    groupId?: string | null;
    agentName?: string | null;
  }) {
    this.logger.log(
      `Broadcasting assignment: ${event.conversationId} → agent=${event.agentId ?? 'unassigned'}, group=${event.groupId ?? 'unchanged'}`,
    );

    // Resolve agent name if not provided by the emitter
    let agentName = event.agentName ?? null;
    if (event.agentId && !agentName) {
      try {
        const users = await this.usersService.findByIdsGlobal([event.agentId]);
        const u = users[0];
        agentName = u
          ? [u.firstName, u.lastName].filter(Boolean).join(' ').trim() ||
            u.email ||
            null
          : null;
      } catch {
        agentName = null;
      }
    }

    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:assigned', {
        conversationId: event.conversationId,
        agentId: event.agentId,
        agentName,
        oldAgentId: event.oldAgentId,
        groupId: event.groupId,
        timestamp: new Date().toISOString(),
      });
  }

  @OnEvent('omni.bot.disabled')
  handleBotDisabled(event: {
    tenantId: string;
    conversationId: string;
    reason: string;
  }) {
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:bot_state', {
        conversationId: event.conversationId,
        bot: { enabled: false, status: 'handoff' },
        reason: event.reason,
        timestamp: new Date().toISOString(),
      });
  }

  @OnEvent('omni.bot.enabled')
  handleBotEnabled(event: { tenantId: string; conversationId: string }) {
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:bot_state', {
        conversationId: event.conversationId,
        bot: { enabled: true, status: 'active' },
        timestamp: new Date().toISOString(),
      });
  }

  @OnEvent('omni.conversation.lock_acquired')
  handleLockAcquired(event: any) {
    const payload = this.standardEvent('conversation.lock_acquired', event);
    this.server
      .to(`tenant:${event.tenantId}:conversation:${event.conversationId}`)
      .emit('conversation.lock_acquired', payload);
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:locked', {
        conversationId: event.conversationId,
        lockedBy: event.agentId,
        lockedByName: event.agentName,
        expiresAt: event.expiresAt,
      });
  }

  @OnEvent('omni.conversation.lock_released')
  handleLockReleased(event: any) {
    const payload = this.standardEvent('conversation.lock_released', event);
    this.server
      .to(`tenant:${event.tenantId}:conversation:${event.conversationId}`)
      .emit('conversation.lock_released', payload);
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:unlocked', {
        conversationId: event.conversationId,
        agentId: event.agentId,
        releasedAt: event.releasedAt,
      });
  }

  @OnEvent('omni.conversation.takeover')
  handleTakeover(event: any) {
    const payload = this.standardEvent('conversation.takeover', event);
    this.server
      .to(`tenant:${event.tenantId}:conversation:${event.conversationId}`)
      .emit('conversation.takeover', payload);

    if (event.previousAgentId) {
      this.server
        .to(`agent:${event.previousAgentId}`)
        .emit('conversation.takeover', payload);
    }
    this.server
      .to(`agent:${event.newAgentId}`)
      .emit('conversation.takeover', payload);

    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:takeover', {
        conversationId: event.conversationId,
        previousAgentId: event.previousAgentId,
        newAgentId: event.newAgentId,
        newAgentName: event.newAgentName,
        reason: event.reason,
        occurredAt: event.occurredAt,
      });
  }

  /**
   * Broadcast new note creation to agents watching the conversation.
   */
  @OnEvent('omni.conversation.note_added')
  handleNoteAdded(event: {
    tenantId: string;
    conversationId: string;
    noteId: string;
    authorId: string;
    authorName?: string;
    isPrivate: boolean;
    content: string;
  }) {
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:conversation:note_added', {
        conversationId: event.conversationId,
        noteId: event.noteId,
        authorId: event.authorId,
        authorName: event.authorName,
        isPrivate: event.isPrivate,
        content: event.content,
        timestamp: new Date().toISOString(),
      });
  }

  // ─── Activity (Audit Trail) real-time broadcast ─────────────────

  /**
   * Broadcast new activity log entries to the tenant room.
   * This enables inline system messages in the ChatWindow
   * (e.g. "Hệ thống đã gán cuộc hội thoại cho Nguyễn Văn A").
   */
  @OnEvent('omni.activity.created')
  handleActivityCreated(event: {
    tenantId: string;
    conversationId: string;
    activity: any;
  }) {
    if (!event.tenantId) return;
    const room = `tenant:${event.tenantId}`;
    this.logger.debug(
      `Broadcasting activity "${event.activity?.action}" for conversation ${event.conversationId}`,
    );
    this.server.to(room).emit('omni:activity:new', {
      conversationId: event.conversationId,
      activity: event.activity,
    });
  }

  private standardEvent(eventName: string, payload: any) {
    return {
      eventId: ulid(),
      event: eventName,
      conversationId: payload.conversationId,
      occurredAt: payload.occurredAt ?? new Date().toISOString(),
      version: Date.now(),
      payload,
    };
  }

  private async publishSocketEvent(channel: string, payload: unknown) {
    await this.redis.publish(channel, JSON.stringify(payload));
  }

  private normalizeHost(host?: string): string {
    return (host ?? '').toLowerCase().replace(/\.$/, '');
  }

  /**
   * Broadcasts CSAT submission to the agent who handled the conversation.
   * Emitted by CsatService when a customer submits their satisfaction rating.
   *
   * Socket events:
   *   - `omni:csat:received` → tenant room (dashboard widgets)
   *   - `omni:csat:received` → agent:${agentId} room (personal notification)
   */
  @OnEvent('csat.submitted')
  handleCsatSubmitted(event: {
    tenantId: string;
    conversationId: string;
    agentId: string | null;
    score: number;
    comment?: string;
    submittedAt: Date;
  }) {
    this.logger.log(
      `CSAT received: conversation=${event.conversationId} score=${event.score}`,
    );

    const payload = {
      conversationId: event.conversationId,
      score: event.score,
      comment: event.comment ?? null,
      submittedAt: event.submittedAt.toISOString(),
    };

    // Broadcast to entire tenant (for dashboard live updates)
    this.server
      .to(`tenant:${event.tenantId}`)
      .emit('omni:csat:received', payload);

    // Also notify the specific agent for personal alert
    if (event.agentId) {
      this.server
        .to(`agent:${event.agentId}`)
        .emit('omni:csat:received', payload);
    }
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { Cron, CronExpression } from '@nestjs/schedule';
import { AgentPresenceService } from './agent-presence.service';
import { ConversationRepository } from '../repositories/conversation.repository';
import {
  tenantPresenceHashKey,
  tenantAgentLoadKey,
} from '../domain/agent-presence';

/**
 * PresenceReconciliationService — self-healing guard for Redis agent counters.
 *
 * Problem (P0):
 *   The Redis presence hash stores `activeConversations` for each agent.
 *   This counter is incremented/decremented atomically by Lua scripts during
 *   assign/release operations. However, if Redis is flushed, restarted, or a
 *   network partition causes a missed release, the counter drifts permanently.
 *   Drifted counters cause agents to appear "full" with phantom conversations,
 *   silently blocking new assignments until a manual Redis flush.
 *
 * Solution:
 *   1. On-demand reconcile: called whenever an agent reconnects (the most
 *      important case — after a Redis flush + agent reconnect, counters reset).
 *   2. Periodic reconcile: scheduled cron every 5 minutes to self-heal any
 *      drift that accumulated without a reconnect event.
 *
 * Algorithm:
 *   For each agent in the tenant's presence hash:
 *     actual = MongoDB countDocuments(assignedAgentId, status in [open, pending])
 *     if redis.activeConversations !== actual → patch Redis to actual value
 *
 * Performance:
 *   - Uses `countOpenByAgents()` which runs a single aggregation pipeline
 *     for all agents in the tenant (not N individual queries).
 *   - Only writes to Redis when drift is detected (no-op for healthy state).
 *   - Cron is scoped to tenants that have active agents in Redis, not all tenants.
 */
@Injectable()
export class PresenceReconciliationService {
  private readonly logger = new Logger(PresenceReconciliationService.name);

  constructor(
    private readonly presenceService: AgentPresenceService,
    private readonly conversationRepo: ConversationRepository,
  ) {}

  /**
   * Reconcile presence counters for a single agent immediately.
   * Called by the gateway when an agent reconnects.
   *
   * @param tenantId  - tenant owning the agent
   * @param agentId   - the reconnecting agent's user ID
   */
  async reconcileAgent(tenantId: string, agentId: string): Promise<void> {
    try {
      const presence = await this.presenceService.getPresence(
        tenantId,
        agentId,
      );
      if (!presence) return; // agent not in Redis — nothing to reconcile

      const actual = await this.conversationRepo.countOpenByAgent(
        tenantId,
        agentId,
      );
      const stored = presence.activeConversations ?? 0;

      if (stored !== actual) {
        this.logger.warn(
          `Presence drift detected for agent ${agentId} (tenant ${tenantId}): ` +
            `Redis=${stored}, MongoDB=${actual} — patching`,
        );
        await this.presenceService.patchActiveConversations(
          tenantId,
          agentId,
          actual,
        );
      } else {
        this.logger.debug(
          `Agent ${agentId} presence counter OK (activeConversations=${actual})`,
        );
      }
    } catch (err: any) {
      this.logger.error(
        `Failed to reconcile presence for agent ${agentId}: ${err.message}`,
      );
    }
  }

  /**
   * Reconcile presence counters for ALL agents in a tenant.
   * Called by the periodic cron or manually by ops tooling.
   *
   * @param tenantId - tenant to reconcile
   * @returns number of agents whose counters were patched
   */
  async reconcileTenant(tenantId: string): Promise<number> {
    const allAgents = await this.presenceService.getAllAgents(tenantId);
    if (allAgents.length === 0) return 0;

    const agentIds = allAgents.map((a) => a.userId);

    // Batch aggregation — single MongoDB round-trip for all agents
    const actualCounts = await this.conversationRepo.countOpenByAgents(
      tenantId,
      agentIds,
    );

    let patchedCount = 0;
    const patches: Promise<void>[] = [];

    for (const presence of allAgents) {
      const actual = actualCounts.get(presence.userId) ?? 0;
      const stored = presence.activeConversations ?? 0;

      if (stored !== actual) {
        this.logger.warn(
          `[Reconcile] Agent ${presence.userId} drift: Redis=${stored}, MongoDB=${actual}`,
        );
        patches.push(
          this.presenceService
            .patchActiveConversations(tenantId, presence.userId, actual)
            .catch((err: any) =>
              this.logger.error(
                `Failed to patch agent ${presence.userId}: ${err.message}`,
              ),
            ),
        );
        patchedCount++;
      }
    }

    if (patches.length > 0) {
      await Promise.allSettled(patches);
      this.logger.log(
        `[Reconcile] Tenant ${tenantId}: patched ${patchedCount}/${allAgents.length} agents`,
      );
    } else {
      this.logger.debug(
        `[Reconcile] Tenant ${tenantId}: all ${allAgents.length} agents OK`,
      );
    }

    return patchedCount;
  }

  /**
   * Periodic cron: reconcile all tenants with active agents in Redis.
   * Runs every 5 minutes. Detects drift that accumulates without reconnect events.
   *
   * Scope: only tenants that have at least one active agent in the Redis
   * presence hash. Tenants with no agents are skipped.
   */
  @Cron(CronExpression.EVERY_5_MINUTES)
  async reconcileAllTenants(): Promise<void> {
    this.logger.debug(
      '[Reconcile] Starting periodic presence reconciliation...',
    );
    try {
      const tenantIds =
        await this.conversationRepo.findDistinctTenantIdsWithActiveConversations();

      if (tenantIds.length === 0) {
        this.logger.debug('[Reconcile] No active tenants found');
        return;
      }

      let totalPatched = 0;
      for (const tenantId of tenantIds) {
        try {
          const patched = await this.reconcileTenant(tenantId);
          totalPatched += patched;
        } catch (err: any) {
          this.logger.error(
            `[Reconcile] Failed for tenant ${tenantId}: ${err.message}`,
          );
        }
      }

      this.logger.log(
        `[Reconcile] Completed. Tenants scanned: ${tenantIds.length}, agents patched: ${totalPatched}`,
      );
    } catch (err: any) {
      this.logger.error(`[Reconcile] Cron failed: ${err.message}`, err.stack);
    }
  }
}

import { Injectable, Logger, Inject } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import * as nodemailer from 'nodemailer';
import * as cheerio from 'cheerio';
import axios from 'axios';
import { ulid } from 'ulid';
import { MessageRepository } from '../omni-inbound/repositories/message.repository';
import { ConversationRepository } from '../omni-inbound/repositories/conversation.repository';
import { TransportPoolService } from '../channels/transport-pool.service';
import { OutboundQueueService } from '../channels/services/outbound-queue.service';
import { EmailSignatureService } from '../channels/services/email-signature.service';
import { UsersService } from '../users/users.service';
import { EmailContentDocument } from '../channels/infrastructure/persistence/document/entities/email-content.schema';
import { EmailMetadataDocument } from '../channels/infrastructure/persistence/document/entities/email-metadata.schema';

/**
 * T-041: OutboundEmailHandler
 *
 * Extracted from OutboundService to isolate email/SMTP-specific concerns:
 * - SMTP transport resolution
 * - Outbound throttle & daily quota check
 * - HTML parsing + CID inline image embedding (cheerio)
 * - Email signature append
 * - Nodemailer send
 * - EmailContent + EmailMetadata persistence
 *
 * Reduces OutboundService by ~290 lines.
 */
@Injectable()
export class OutboundEmailHandler {
  private readonly logger = new Logger(OutboundEmailHandler.name);

  constructor(
    private readonly messageRepo: MessageRepository,
    private readonly conversationRepo: ConversationRepository,
    private readonly eventEmitter: EventEmitter2,
    private readonly transportPool: TransportPoolService,
    private readonly outboundQueue: OutboundQueueService,
    private readonly emailSignatureService: EmailSignatureService,
    private readonly usersService: UsersService,
    @InjectModel('EmailContentSchemaClass')
    private readonly emailContentModel: Model<EmailContentDocument>,
    @InjectModel('EmailMetadataSchemaClass')
    private readonly emailMetadataModel: Model<EmailMetadataDocument>,
  ) {}

  async sendEmailReply(params: {
    tenantId: string;
    conversationId: string;
    agentId: string;
    to: string[];
    cc?: string[];
    bcc?: string[];
    subject: string;
    htmlBody: string;
    inReplyTo?: string;
    references?: string[];
    attachments?: { url: string; filename: string; contentType: string }[];
  }): Promise<any> {
    const {
      tenantId,
      conversationId,
      agentId,
      to,
      cc = [],
      bcc = [],
      subject,
      htmlBody,
      inReplyTo,
      references = [],
      attachments: standardAttachments = [],
    } = params;
    const senderContext = await this.resolveSenderContext(agentId);

    const conversation = await this.conversationRepo.findById(conversationId);
    if (!conversation) {
      throw new Error(`Conversation ${conversationId} not found`);
    }

    // 1. Resolve SMTP config from TransportPool
    const channelId = conversation.channelId.toString();
    const transportConfig = await this.transportPool.resolveWithTenantGuard(
      channelId,
      tenantId,
    );

    if (!transportConfig || transportConfig.providerType !== 'smtp') {
      throw new Error('Invalid or missing SMTP configuration for this channel');
    }

    const { user, password } = transportConfig.credentials;
    const { host, port, fromEmail, fromName } = transportConfig.publicSettings;
    const numPort = Number(port);

    // ── Outbound Queue: Throttle + Daily Quota Check ──────────────────
    const throttleResult = await this.outboundQueue.checkSendAllowed(
      tenantId,
      channelId,
      host,
      to.length + cc.length + bcc.length,
    );
    if (!throttleResult.allowed) {
      throw new Error(throttleResult.reason || 'Send rate limited');
    }

    const transporter = nodemailer.createTransport({
      host,
      port: numPort,
      secure: numPort === 465,
      auth: { user, pass: password },
    });

    // 2. PARSE HTML & PROCESS CID INLINE IMAGES
    const $ = cheerio.load(htmlBody);
    const imagesToProcess = $('img').toArray();
    const inlineAttachments: any[] = [];

    for (const [index, el] of imagesToProcess.entries()) {
      const src = $(el).attr('src');
      if (src && src.includes('s3')) {
        const cid = `inline-${index}-${Date.now()}@crmsaudi.dev`;
        $(el).attr('src', `cid:${cid}`);

        try {
          const response = await axios({
            method: 'get',
            url: src,
            responseType: 'stream',
          });

          inlineAttachments.push({
            cid,
            filename: `image-${index}.jpg`,
            content: response.data,
            contentType: response.headers['content-type'],
          });
        } catch (downloadErr: unknown) {
          const errorMessage =
            downloadErr instanceof Error
              ? downloadErr.message
              : String(downloadErr);
          this.logger.warn(
            `Failed to download inline image from ${src}: ${errorMessage}`,
          );
          $(el).attr('src', src);
        }
      }
    }

    // ── Append Email Signature + Signature Fence ───────────────────────
    const signature = await this.emailSignatureService.getSignature(
      tenantId,
      agentId,
      channelId,
    );
    const signatureHtml = signature?.htmlContent || '';
    const signatureFenceHtml =
      this.emailSignatureService.wrapWithSignatureFence(
        signatureHtml,
        conversationId,
      );
    if ($('body').length) {
      $('body').append(signatureFenceHtml);
    } else {
      $.root().append(signatureFenceHtml);
    }

    const finalHtml = $.html();

    // Setup standard attachments via streams
    const formattedAttachments: any[] = [];
    for (const attachment of standardAttachments) {
      try {
        const response = await axios({
          method: 'get',
          url: attachment.url,
          responseType: 'stream',
        });
        formattedAttachments.push({
          filename: attachment.filename,
          content: response.data,
          contentType: attachment.contentType,
        });
      } catch {
        this.logger.error(`Failed to download attachment ${attachment.url}`);
        throw new Error(
          `Could not fetch attachment ${attachment.filename} for email dispatch`,
        );
      }
    }

    const allAttachments = [...formattedAttachments, ...inlineAttachments];

    // 3. Persist placeholder to MessageRepository
    const snippet =
      finalHtml
        .replace(/<[^>]*>?/gm, '')
        .substring(0, 200)
        .trim() || '(No content)';

    let messageRecord;
    try {
      messageRecord = await this.messageRepo.create({
        tenantId,
        conversationId,
        senderId: agentId,
        senderName: senderContext.name,
        senderAvatarUrl: senderContext.avatarUrl ?? undefined,
        senderType: 'agent',
        direction: 'outbound',
        source: 'crm_api',
        messageType: 'text',
        content: snippet,
        status: 'sending',
        metadata: {
          sender: {
            id: agentId,
            name: senderContext.name,
            avatarUrl: senderContext.avatarUrl ?? null,
            type: 'agent',
          },
          source: 'crm_api',
        },
      });
    } catch (dbErr) {
      throw new Error(`Failed to create message record: ${dbErr}`);
    }

    // 4. Send Email via NodeMailer
    let info;
    const fromAddress = fromName ? `"${fromName}" <${fromEmail}>` : fromEmail;
    try {
      info = await transporter.sendMail({
        from: fromAddress,
        to,
        cc,
        bcc,
        subject,
        html: `<html><head><meta charset="utf-8"></head><body>${finalHtml}</body></html>`,
        text: snippet,
        attachments: allAttachments,
        inReplyTo: inReplyTo || undefined,
        references: references.length ? references.join(' ') : undefined,
        headers: {
          'X-CRM-Thread-ID': conversationId,
          'X-CRM-Tenant-ID': tenantId,
          'X-CRM-Message-Id': messageRecord.id,
        },
      });
    } catch (err) {
      this.logger.error(`Nodemailer failed to send email: ${err}`);
      await this.messageRepo.updateStatus(messageRecord.id, 'failed');
      throw err;
    }

    const externalId = info.messageId || `<${ulid()}@crm.local>`;

    // 5. Update Status + Record Send for Quota Tracking
    await this.messageRepo.updateStatus(messageRecord.id, 'sent', externalId);
    await this.conversationRepo.updateLastMessage(
      conversationId,
      snippet,
      new Date(),
      'agent',
    );

    await this.outboundQueue.recordSend(
      tenantId,
      channelId,
      to.length + cc.length + bcc.length,
    );

    // 6. Save Email Full Content & Metadata
    await this.emailContentModel.create({
      tenantId,
      messageId: messageRecord.id,
      contactIds: [],
      subject,
      htmlBody: finalHtml,
      textBody: snippet,
      attachments: standardAttachments,
    });

    await this.emailMetadataModel.create({
      tenantId,
      mailboxId: channelId,
      messageId: messageRecord.id,
      emailMessageId: externalId,
      inReplyTo,
      references,
      from: fromAddress,
      to,
      cc,
      bcc,
      deliveryStatus: 'unknown',
    });

    // 7. Emit real-time socket event
    this.eventEmitter.emit('omni.message.sent', {
      tenantId,
      conversationId,
      senderId: agentId,
      senderName: senderContext.name,
      senderAvatarUrl: senderContext.avatarUrl ?? null,
      senderType: 'agent',
      messageType: 'text',
      content: snippet,
      messageId: messageRecord.id,
      externalMessageId: externalId,
      status: 'sent',
      timestamp: new Date().toISOString(),
      source: 'crm_api',
      transport: 'http',
    });

    return {
      ok: true,
      messageId: messageRecord.id,
      externalMessageId: externalId,
    };
  }

  // ── Shared Helpers ──────────────────────────────────────────────────────

  private async resolveSenderContext(agentId: string): Promise<{
    name: string;
    avatarUrl?: string | null;
  }> {
    try {
      const users = await this.usersService.findByIdsGlobal([agentId]);
      const user = users[0];
      if (!user) return { name: 'Agent', avatarUrl: null };

      const fullName = [user.firstName, user.lastName]
        .filter(Boolean)
        .join(' ')
        .trim();

      return {
        name: fullName || user.email || 'Agent',
        avatarUrl: user.photo?.path ?? null,
      };
    } catch (error) {
      this.logger.warn(
        `Failed to resolve sender context for agent ${agentId}: ${
          error instanceof Error ? error.message : String(error)
        }`,
      );
      return { name: 'Agent', avatarUrl: null };
    }
  }
}

import { Injectable, Logger, Inject } from '@nestjs/common';
import { ConfigType } from '@nestjs/config';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { MessageRepository } from '../omni-inbound/repositories/message.repository';
import { ConversationRepository } from '../omni-inbound/repositories/conversation.repository';
import {
  ChannelAdapter,
  CHANNEL_ADAPTERS,
} from '../omni-inbound/adapters/channel-adapter.interface';
import { ChannelType } from '../omni-inbound/domain/omni-payload';
import { OutboundMedia } from './types/outbound-media.type';
import { FilesService } from '../files/files.service';
import { ImageProcessingService } from '../files/image-processing.service';
import { PLATFORM_LIMITS } from '../files/config/platform-limits.config';
import { mimeToMessageType } from '../common/utils/mime.util';
import { OutboundMediaHandler } from './outbound-media.handler';
import { OutboundEmailHandler } from './outbound-email.handler';

import { ChannelRepository } from '../channels/infrastructure/persistence/document/repositories/channel.repository';
import { ReplyWindowExpiredException } from './exceptions/reply-window-expired.exception';
import replyWindowConfig from './config/reply-window.config';

import { TransportPoolService } from '../channels/transport-pool.service';
import { OutboundQueueService } from '../channels/services/outbound-queue.service';
import { EmailSignatureService } from '../channels/services/email-signature.service';
import { InjectModel } from '@nestjs/mongoose';
import { Model } from 'mongoose';
import { EmailContentDocument } from '../channels/infrastructure/persistence/document/entities/email-content.schema';
import { EmailMetadataDocument } from '../channels/infrastructure/persistence/document/entities/email-metadata.schema';
import * as nodemailer from 'nodemailer';
